```typescript
export type BookLoanState =
  | { status: "none" }
  | { status: "checkedOut"; id: string; patron: string; dueOn: string; renewals: number }
  | { status: "returned"; id: string; returnedOn: string }
  | { status: "lost"; id: string; reportedOn: string };

export type BookLoanCommand =
  | { type: "checkOut"; id: string; patron: string; dueOn: string }
  | { type: "renew"; newDueOn: string }
  | { type: "returnBook"; on: string }
  | { type: "reportLost"; on: string };

export type BookLoanEvent =
  | { type: "CheckedOut"; id: string; patron: string; dueOn: string }
  | { type: "Renewed"; dueOn: string }
  | { type: "Returned"; on: string }
  | { type: "LostReported"; on: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const initialState: BookLoanState = { status: "none" };

export function decide(command: BookLoanCommand, state: BookLoanState): BookLoanEvent[] {
  switch (command.type) {
    case "checkOut":
      if (state.status !== "none") throw new DomainError("already checked out");
      return [{ type: "CheckedOut", id: command.id, patron: command.patron, dueOn: command.dueOn }];
    case "renew":
      if (state.status !== "checkedOut") throw new DomainError("not checked out");
      if (state.renewals >= 3) throw new DomainError("renewal limit");
      return [{ type: "Renewed", dueOn: command.newDueOn }];
    case "returnBook":
      if (state.status === "returned") throw new DomainError("already returned");
      if (state.status !== "checkedOut") throw new DomainError("nothing to return");
      return [{ type: "Returned", on: command.on }];
    case "reportLost":
      if (state.status !== "checkedOut") throw new DomainError("not on loan");
      return [{ type: "LostReported", on: command.on }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: BookLoanState, event: BookLoanEvent): BookLoanState {
  switch (event.type) {
    case "CheckedOut":
      return { status: "checkedOut", id: event.id, patron: event.patron, dueOn: event.dueOn, renewals: 0 };
    case "Renewed":
      return state.status === "checkedOut" ? { ...state, dueOn: event.dueOn, renewals: state.renewals + 1 } : state;
    case "Returned":
      return state.status === "checkedOut" ? { status: "returned", id: state.id, returnedOn: event.on } : state;
    case "LostReported":
      return state.status === "checkedOut" ? { status: "lost", id: state.id, reportedOn: event.on } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const bookLoanDecider: Decider<BookLoanCommand, BookLoanEvent, BookLoanState> = {
  initialState,
  decide,
  evolve,
};
```

A Decider<C,E,S> bundles initialState, decide(command,state) returning events, and evolve(state,event) returning the next state. Both switch functions use a never-default so the compiler catches new variants.

```typescript
export type LibraryBranchState =
  | { status: "planned"; id: string; code: string }
  | { status: "open"; id: string; code: string; holidays: number }
  | { status: "closed"; id: string; closedOn: string }
  | { status: "archived"; id: string };

export type LibraryBranchCommand =
  | { type: "plan"; id: string; code: string }
  | { type: "open" }
  | { type: "markHoliday" }
  | { type: "close"; on: string }
  | { type: "archive" };

export type LibraryBranchEvent =
  | { type: "Planned"; id: string; code: string }
  | { type: "Opened" }
  | { type: "HolidayMarked" }
  | { type: "Closed"; on: string }
  | { type: "Archived" };

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export class DomainError extends Error {}

export const branchDecider: Decider<LibraryBranchCommand, LibraryBranchEvent, LibraryBranchState> = {
  initialState: { status: "planned", id: "", code: "" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        return [{ type: "Planned", id: command.id, code: command.code }];
      case "open":
        if (state.status !== "planned") throw new DomainError("cannot open");
        return [{ type: "Opened" }];
      case "markHoliday":
        if (state.status !== "open") throw new DomainError("not open");
        return [{ type: "HolidayMarked" }];
      case "close":
        if (state.status !== "open") throw new DomainError("not open");
        return [{ type: "Closed", on: command.on }];
      case "archive":
        if (state.status !== "closed") throw new DomainError("must close first");
        return [{ type: "Archived" }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Planned":
        return { status: "planned", id: event.id, code: event.code };
      case "Opened":
        return state.status === "planned" ? { status: "open", id: state.id, code: state.code, holidays: 0 } : state;
      case "HolidayMarked":
        return state.status === "open" ? { ...state, holidays: state.holidays + 1 } : state;
      case "Closed":
        return state.status === "open" ? { status: "closed", id: state.id, closedOn: event.on } : state;
      case "Archived":
        return state.status === "closed" ? { status: "archived", id: state.id } : state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
