```typescript
export type AcquisitionOrderState =
  | { status: "draft"; id: string; vendor: string; lines: number }
  | { status: "placed"; id: string; vendor: string; lines: number; placedOn: string }
  | { status: "received"; id: string; receivedOn: string }
  | { status: "cancelled"; id: string; reason: string };

export type AcquisitionOrderCommand =
  | { type: "draft"; id: string; vendor: string }
  | { type: "addLine" }
  | { type: "place"; on: string }
  | { type: "receive"; on: string }
  | { type: "cancel"; reason: string };

export type AcquisitionOrderEvent =
  | { type: "Drafted"; id: string; vendor: string }
  | { type: "LineAdded" }
  | { type: "Placed"; on: string }
  | { type: "Received"; on: string }
  | { type: "Cancelled"; reason: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const initialState: AcquisitionOrderState = { status: "draft", id: "", vendor: "", lines: 0 };

export function decide(command: AcquisitionOrderCommand, state: AcquisitionOrderState): AcquisitionOrderEvent[] {
  switch (command.type) {
    case "draft":
      return [{ type: "Drafted", id: command.id, vendor: command.vendor }];
    case "addLine":
      if (state.status !== "draft") throw new DomainError("not a draft");
      return [{ type: "LineAdded" }];
    case "place":
      if (state.status !== "draft") throw new DomainError("not a draft");
      if (state.lines === 0) throw new DomainError("no lines");
      return [{ type: "Placed", on: command.on }];
    case "receive":
      if (state.status !== "placed") throw new DomainError("order was never placed");
      return [{ type: "Received", on: command.on }];
    case "cancel":
      if (state.status === "received") throw new DomainError("already received");
      return [{ type: "Cancelled", reason: command.reason }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: AcquisitionOrderState, event: AcquisitionOrderEvent): AcquisitionOrderState {
  switch (event.type) {
    case "Drafted":
      return { status: "draft", id: event.id, vendor: event.vendor, lines: 0 };
    case "LineAdded":
      return state.status === "draft" ? { ...state, lines: state.lines + 1 } : state;
    case "Placed":
      return state.status === "draft" ? { ...state, status: "placed", placedOn: event.on } : state;
    case "Received":
      return state.status === "placed" ? { status: "received", id: state.id, receivedOn: event.on } : state;
    case "Cancelled":
      return { status: "cancelled", id: "id" in state ? state.id : "", reason: event.reason };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export const acquisitionDecider: Decider<AcquisitionOrderCommand, AcquisitionOrderEvent, AcquisitionOrderState> = {
  initialState,
  decide,
  evolve,
};
```

A Decider exposes initialState plus two pure functions. decide(command, state) validates invariants (e.g. you cannot publish an issue that was never added) and returns the resulting events. evolve(state, event) folds one event into the next state. Because both are pure, tests are trivial and the verifier can replay any event stream deterministically.

```typescript
export type PeriodicalState = {
  id: string;
  title: string;
  issues: Record<string, "added" | "published">;
};

export type PeriodicalCommand =
  | { type: "register"; id: string; title: string }
  | { type: "addIssue"; issueId: string }
  | { type: "publishIssue"; issueId: string };

export type PeriodicalEvent =
  | { type: "Registered"; id: string; title: string }
  | { type: "IssueAdded"; issueId: string }
  | { type: "IssuePublished"; issueId: string };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const periodicalDecider: Decider<PeriodicalCommand, PeriodicalEvent, PeriodicalState> = {
  initialState: { id: "", title: "", issues: {} },
  decide(command, state) {
    switch (command.type) {
      case "register":
        if (state.id !== "") throw new DomainError("already registered");
        return [{ type: "Registered", id: command.id, title: command.title }];
      case "addIssue":
        if (state.id === "") throw new DomainError("not registered");
        if (state.issues[command.issueId]) throw new DomainError("duplicate issue");
        return [{ type: "IssueAdded", issueId: command.issueId }];
      case "publishIssue":
        if (state.issues[command.issueId] !== "added") throw new DomainError("issue not added");
        return [{ type: "IssuePublished", issueId: command.issueId }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Registered":
        return { id: event.id, title: event.title, issues: {} };
      case "IssueAdded":
        return { ...state, issues: { ...state.issues, [event.issueId]: "added" } };
      case "IssuePublished":
        return { ...state, issues: { ...state.issues, [event.issueId]: "published" } };
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
```

The existing decider has create, schedule, and complete.  I add a Suspend command plus a SessionSuspended event, a guard that only an active group can be suspended, and a new status 'suspended' with a resume command to restore it.

```typescript
export type ReadingGroupState =
  | { status: "none" }
  | { status: "active"; id: string; members: number }
  | { status: "suspended"; id: string; suspendedOn: string }
  | { status: "completed"; id: string };

export type ReadingGroupCommand =
  | { type: "create"; id: string }
  | { type: "join" }
  | { type: "suspend"; on: string }
  | { type: "resume" }
  | { type: "complete" };

export type ReadingGroupEvent =
  | { type: "Created"; id: string }
  | { type: "Joined" }
  | { type: "SessionSuspended"; on: string }
  | { type: "Resumed" }
  | { type: "Completed" };

export class DomainError extends Error {}

export interface Decider<C, E, S> {
  initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const readingGroupDecider: Decider<ReadingGroupCommand, ReadingGroupEvent, ReadingGroupState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("already created");
        return [{ type: "Created", id: command.id }];
      case "join":
        if (state.status !== "active") throw new DomainError("not active");
        return [{ type: "Joined" }];
      case "suspend":
        if (state.status !== "active") throw new DomainError("not active");
        return [{ type: "SessionSuspended", on: command.on }];
      case "resume":
        if (state.status !== "suspended") throw new DomainError("not suspended");
        return [{ type: "Resumed" }];
      case "complete":
        if (state.status === "completed") throw new DomainError("already completed");
        return [{ type: "Completed" }];
      default: {
        const _: never = command;
        return _;
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "Created":
        return { status: "active", id: event.id, members: 0 };
      case "Joined":
        return state.status === "active" ? { ...state, members: state.members + 1 } : state;
      case "SessionSuspended":
        return state.status === "active" ? { status: "suspended", id: state.id, suspendedOn: event.on } : state;
      case "Resumed":
        return state.status === "suspended" ? { status: "active", id: state.id, members: 0 } : state;
      case "Completed":
        return "id" in state ? { status: "completed", id: state.id } : state;
      default: {
        const _: never = event;
        return _;
      }
    }
  },
};
```

The prior implementation fell through to an implicit return and did not guard the cancelled state. Below is the corrected typed Decider pair.

```typescript
export type ReferenceRequestState =
  | { status: "open"; id: string; topic: string }
  | { status: "answered"; id: string; answeredOn: string }
  | { status: "cancelled"; id: string; reason: string };

export type ReferenceRequestCommand =
  | { type: "open"; id: string; topic: string }
  | { type: "answer"; on: string }
  | { type: "cancel"; reason: string };

export type ReferenceRequestEvent =
  | { type: "Opened"; id: string; topic: string }
  | { type: "Answered"; on: string }
  | { type: "Cancelled"; reason: string };

export class DomainError extends Error {}

export function decide(command: ReferenceRequestCommand, state: ReferenceRequestState): ReferenceRequestEvent[] {
  switch (command.type) {
    case "open":
      return [{ type: "Opened", id: command.id, topic: command.topic }];
    case "answer":
      if (state.status === "cancelled") throw new DomainError("request cancelled");
      if (state.status !== "open") throw new DomainError("not open");
      return [{ type: "Answered", on: command.on }];
    case "cancel":
      if (state.status !== "open") throw new DomainError("cannot cancel");
      return [{ type: "Cancelled", reason: command.reason }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export function evolve(state: ReferenceRequestState, event: ReferenceRequestEvent): ReferenceRequestState {
  switch (event.type) {
    case "Opened":
      return { status: "open", id: event.id, topic: event.topic };
    case "Answered":
      return state.status === "open" ? { status: "answered", id: state.id, answeredOn: event.on } : state;
    case "Cancelled":
      return state.status === "open" ? { status: "cancelled", id: state.id, reason: event.reason } : state;
    default: {
      const _: never = event;
      return _;
    }
  }
}
