```typescript
export type CatalogEvent =
  | { type: "TitleAdded"; titleId: string; genre: string }
  | { type: "TitleRemoved"; titleId: string; genre: string }
  | { type: "TitleRenamed"; titleId: string; name: string }
  | { type: "CatalogPublished" };

export type CatalogView = Readonly<{
  titles: Record<string, { id: string; name: string; genre: string }>;
  totalsByGenre: Record<string, number>;
}>;

export const emptyView: CatalogView = { titles: {}, totalsByGenre: {} };

function bump(totals: Record<string, number>, genre: string, delta: number): Record<string, number> {
  const current = totals[genre] ?? 0;
  const next = current + delta;
  if (next <= 0) {
    const { [genre]: _drop, ...rest } = totals;
    return rest;
  }
  return { ...totals, [genre]: next };
}

export function project(view: CatalogView, event: CatalogEvent): CatalogView {
  switch (event.type) {
    case "TitleAdded":
      return {
        titles: { ...view.titles, [event.titleId]: { id: event.titleId, name: "", genre: event.genre } },
        totalsByGenre: bump(view.totalsByGenre, event.genre, +1),
      };
    case "TitleRemoved": {
      const { [event.titleId]: _removed, ...rest } = view.titles;
      return { titles: rest, totalsByGenre: bump(view.totalsByGenre, event.genre, -1) };
    }
    case "TitleRenamed": {
      const existing = view.titles[event.titleId];
      if (!existing) return view;
      return { ...view, titles: { ...view.titles, [event.titleId]: { ...existing, name: event.name } } };
    }
    case "CatalogPublished":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}
```

A projection is just a fold over a subset of events. I keep one row per loanId, flag it overdue on the checkout event only when the due date is set, clear it on return, and ignore events outside the view's interest (exhaustively).

```typescript
export type OverdueLoanEvent =
  | { type: "LoanCheckedOut"; loanId: string; patron: string; dueOn: string }
  | { type: "LoanReturned"; loanId: string; on: string }
  | { type: "LoanRenewed"; loanId: string; dueOn: string }
  | { type: "BranchOpened" };

export type OverdueLoanView = Readonly<{
  rows: Record<string, { loanId: string; patron: string; dueOn: string }>;
}>;

export const emptyView: OverdueLoanView = { rows: {} };

export function project(view: OverdueLoanView, event: OverdueLoanEvent): OverdueLoanView {
  switch (event.type) {
    case "LoanCheckedOut":
      return {
        rows: {
          ...view.rows,
          [event.loanId]: { loanId: event.loanId, patron: event.patron, dueOn: event.dueOn },
        },
      };
    case "LoanRenewed": {
      const existing = view.rows[event.loanId];
      if (!existing) return view;
      return { rows: { ...view.rows, [event.loanId]: { ...existing, dueOn: event.dueOn } } };
    }
    case "LoanReturned": {
      const { [event.loanId]: _done, ...rest } = view.rows;
      return { rows: rest };
    }
    case "BranchOpened":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}
```

evolve reconstructs one aggregate's state from its own events and is used on the write side.  A projection folds a subset of events across aggregates into a denormalised, query-friendly view on the read side; it should ignore events it does not care about by returning the view unchanged.  The example keeps a per-title subscriber count.

```typescript
export type PeriodicalProjectionEvent =
  | { type: "PeriodicalRegistered"; titleId: string; name: string }
  | { type: "SubscriberJoined"; titleId: string; subscriberId: string }
  | { type: "SubscriberLeft"; titleId: string; subscriberId: string }
  | { type: "IssuePublished"; titleId: string; issueId: string };

export type PeriodicalSubscribersView = Readonly<{
  titles: Record<string, { name: string; subscribers: number }>;
}>;

export const emptyView: PeriodicalSubscribersView = { titles: {} };

export function project(
  view: PeriodicalSubscribersView,
  event: PeriodicalProjectionEvent,
): PeriodicalSubscribersView {
  switch (event.type) {
    case "PeriodicalRegistered":
      return { titles: { ...view.titles, [event.titleId]: { name: event.name, subscribers: 0 } } };
    case "SubscriberJoined": {
      const row = view.titles[event.titleId] ?? { name: "", subscribers: 0 };
      return { titles: { ...view.titles, [event.titleId]: { ...row, subscribers: row.subscribers + 1 } } };
    }
    case "SubscriberLeft": {
      const row = view.titles[event.titleId];
      if (!row) return view;
      const next = Math.max(0, row.subscribers - 1);
      return { titles: { ...view.titles, [event.titleId]: { ...row, subscribers: next } } };
    }
    case "IssuePublished":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}
```

```typescript
export type DeskEvent =
  | { type: "RequestOpened"; id: string; topic: string; opener: string }
  | { type: "RequestAssigned"; id: string; librarian: string }
  | { type: "RequestAnswered"; id: string; on: string }
  | { type: "BranchClosed" };

export type DeskRow = Readonly<{
  id: string;
  topic: string;
  opener: string;
  librarian?: string;
  status: "open" | "assigned" | "answered";
}>;

export type DeskView = Readonly<{ rows: Readonly<Record<string, DeskRow>> }>;

export const emptyView: DeskView = Object.freeze({ rows: {} });

export function project(view: DeskView, event: DeskEvent): DeskView {
  switch (event.type) {
    case "RequestOpened":
      return {
        rows: {
          ...view.rows,
          [event.id]: { id: event.id, topic: event.topic, opener: event.opener, status: "open" },
        },
      };
    case "RequestAssigned": {
      const row = view.rows[event.id];
      if (!row) return view;
      return { rows: { ...view.rows, [event.id]: { ...row, librarian: event.librarian, status: "assigned" } } };
    }
    case "RequestAnswered": {
      const row = view.rows[event.id];
      if (!row) return view;
      return { rows: { ...view.rows, [event.id]: { ...row, status: "answered" } } };
    }
    case "BranchClosed":
      return view;
    default: {
      const _: never = event;
      return _;
    }
  }
}
