```typescript
export type CurrentBookLoan = {
  status: "checkedOut";
  id: string;
  patron: string;
  dueOn: string;
  renewals: number;
};

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 3 as const;

type V1 = Snapshot<{ status: "checkedOut"; id: string; borrower: string; dueOn: string }>;
type V2 = Snapshot<{ status: "checkedOut"; id: string; patron: string; dueOn: string }>;
type V3 = Snapshot<CurrentBookLoan>;

function v1Tov2(snap: V1): V2 {
  return {
    version: 2,
    state: { status: "checkedOut", id: snap.state.id, patron: snap.state.borrower, dueOn: snap.state.dueOn },
  };
}

function v2Tov3(snap: V2): V3 {
  return { version: 3, state: { ...snap.state, renewals: 0 } };
}

export class UnsupportedSnapshotVersion extends Error {}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentBookLoan> {
  let current: Snapshot<unknown> = snap;
  if (current.version === 1) current = v1Tov2(current as V1);
  if (current.version === 2) current = v2Tov3(current as V2);
  if (current.version !== CURRENT_VERSION) {
    throw new UnsupportedSnapshotVersion(`unknown snapshot version: ${current.version}`);
  }
  return current as Snapshot<CurrentBookLoan>;
}
```

Tag every snapshot with a numeric version and a CURRENT_VERSION constant. Write a pure upgrader per source version. The loader runs them in order and a final type assertion ensures the output conforms to the current shape.

```typescript
export type CurrentDigitalCopy = {
  id: string;
  format: "pdf" | "epub";
  pages: number;
  checksum: string;
};

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 3 as const;

type V1 = Snapshot<{ id: string; pages: number }>;
type V2 = Snapshot<{ id: string; format: "pdf" | "epub"; pages: number }>;
type V3 = Snapshot<CurrentDigitalCopy>;

function v1Tov2(snap: V1): V2 {
  return { version: 2, state: { id: snap.state.id, format: "pdf", pages: snap.state.pages } };
}

function v2Tov3(snap: V2): V3 {
  return { version: 3, state: { ...snap.state, checksum: "" } };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDigitalCopy> {
  let current: Snapshot<unknown> = snap;
  if (current.version === 1) current = v1Tov2(current as V1);
  if (current.version === 2) current = v2Tov3(current as V2);
  if (current.version !== CURRENT_VERSION) throw new Error("unsupported snapshot version");
  return current as Snapshot<CurrentDigitalCopy>;
}
