```typescript
import { Effect } from "effect";

export type CurrentCatalog = {
  id: string;
  name: string;
  titles: ReadonlyArray<string>;
  lastRebuiltAt: string;
};

export type Snapshot<S> = { version: number; state: S };

export const CURRENT_VERSION = 2 as const;

type V1 = Snapshot<{ id: string; name: string; titles: ReadonlyArray<string> }>;
type V2 = Snapshot<CurrentCatalog>;

export class UnsupportedSnapshotVersion extends Error {}

function v1Tov2(snap: V1): V2 {
  return { version: 2, state: { ...snap.state, lastRebuiltAt: "1970-01-01T00:00:00Z" } };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentCatalog> {
  let current: Snapshot<unknown> = snap;
  if (current.version === 1) current = v1Tov2(current as V1);
  if (current.version !== CURRENT_VERSION) {
    throw new UnsupportedSnapshotVersion(`unknown version ${current.version}`);
  }
  return current as Snapshot<CurrentCatalog>;
}

export interface SnapshotStore {
  read(streamName: string): Promise<Snapshot<unknown> | null>;
}

export function loadCatalogSnapshot(store: SnapshotStore, streamName: string) {
  return Effect.gen(function* () {
    const raw = yield* Effect.promise(() => store.read(streamName));
    if (raw === null) return null;
    return upgradeSnapshot(raw);
  });
}
```

```typescript
export type AcquisitionEvent = { type: string; data: Readonly<Record<string, unknown>> };

export interface AppendOptions {
  expectedRevision: bigint | "no_stream" | "any";
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: AcquisitionEvent; revision: bigint }>;
  appendToStream(
    streamName: string,
    events: ReadonlyArray<AcquisitionEvent>,
    options: AppendOptions,
  ): Promise<{ nextExpectedRevision: bigint; conflict?: true }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string, public readonly expected: bigint | "no_stream" | "any") {
    super("concurrency conflict on " + streamName);
  }
}

export async function appendWithExpectedRevision(
  store: EventStore,
  streamName: string,
  events: ReadonlyArray<AcquisitionEvent>,
  expected: bigint | "no_stream" | "any",
): Promise<bigint> {
  const result = await store.appendToStream(streamName, events, { expectedRevision: expected });
  if (result.conflict) throw new ConcurrencyConflict(streamName, expected);
  return result.nextExpectedRevision;
}

export async function readCurrentRevision(store: EventStore, streamName: string): Promise<bigint | "no_stream"> {
  let last: bigint | "no_stream" = "no_stream";
  for await (const { revision } of store.readStream(streamName)) {
    last = revision;
  }
  return last;
}
```

Read the stream to learn its current revision, decide new events from the folded state, then appendToStream with expectedRevision equal to that revision.  If the store reports a conflict, surface a typed ConcurrencyConflict so the caller can retry the whole decision.

```typescript
export type FineEvent =
  | { type: "FineIssued"; amount: number }
  | { type: "FinePaid"; amount: number }
  | { type: "FineWaived"; reason: string };

export type FineState = { balance: number; closed: boolean };

export class ConcurrencyConflict extends Error {}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: FineEvent; revision: bigint }>;
  appendToStream(
    streamName: string,
    events: ReadonlyArray<FineEvent>,
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint; conflict?: true }>;
}

function evolve(state: FineState, event: FineEvent): FineState {
  switch (event.type) {
    case "FineIssued":
      return { balance: state.balance + event.amount, closed: false };
    case "FinePaid":
      return { balance: state.balance - event.amount, closed: state.balance - event.amount <= 0 };
    case "FineWaived":
      return { balance: 0, closed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function payFine(store: EventStore, streamName: string, amount: number): Promise<void> {
  let state: FineState = { balance: 0, closed: false };
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of store.readStream(streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  if (state.closed) throw new Error("fine already closed");
  const result = await store.appendToStream(
    streamName,
    [{ type: "FinePaid", amount }],
    { expectedRevision: expected },
  );
  if (result.conflict) throw new ConcurrencyConflict("fine stream moved");
}
```

