```typescript
export type PeriodicalState = { id: string; issues: Record<string, "added" | "published"> };
export type PeriodicalCommand =
  | { type: "register"; id: string }
  | { type: "addIssue"; issueId: string }
  | { type: "publishIssue"; issueId: string };
export type PeriodicalEvent =
  | { type: "Registered"; id: string }
  | { type: "IssueAdded"; issueId: string }
  | { type: "IssuePublished"; issueId: string };

const initialState: PeriodicalState = { id: "", issues: {} };

export class DomainError extends Error {}

function decide(command: PeriodicalCommand, state: PeriodicalState): PeriodicalEvent[] {
  switch (command.type) {
    case "register":
      if (state.id !== "") throw new DomainError("already registered");
      return [{ type: "Registered", id: command.id }];
    case "addIssue":
      if (state.id === "") throw new DomainError("not registered");
      return [{ type: "IssueAdded", issueId: command.issueId }];
    case "publishIssue":
      if (state.issues[command.issueId] !== "added") throw new DomainError("not added");
      return [{ type: "IssuePublished", issueId: command.issueId }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

function evolve(state: PeriodicalState, event: PeriodicalEvent): PeriodicalState {
  switch (event.type) {
    case "Registered":
      return { id: event.id, issues: {} };
    case "IssueAdded":
      return { ...state, issues: { ...state.issues, [event.issueId]: "added" } };
    case "IssuePublished":
      return { ...state, issues: { ...state.issues, [event.issueId]: "published" } };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: PeriodicalEvent; revision: bigint }>;
  appendToStream(
    streamName: string,
    events: ReadonlyArray<PeriodicalEvent>,
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint }>;
}

export async function handle(
  command: PeriodicalCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initialState;
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  const newEvents = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, newEvents, { expectedRevision: expected });
}
```

A command handler orchestrates but does not decide. It reads the stream to rebuild state, asks the pure decide function for events, and appends them with the last-seen revision as expectedRevision.

```typescript
export type ReadingGroupEvent = { type: "Created"; id: string } | { type: "Joined" } | { type: "Completed" };
export type ReadingGroupCommand = { type: "create"; id: string } | { type: "join" } | { type: "complete" };
export type ReadingGroupState = { id: string; members: number; done: boolean };

const initial: ReadingGroupState = { id: "", members: 0, done: false };

function evolve(state: ReadingGroupState, event: ReadingGroupEvent): ReadingGroupState {
  switch (event.type) {
    case "Created":
      return { id: event.id, members: 0, done: false };
    case "Joined":
      return { ...state, members: state.members + 1 };
    case "Completed":
      return { ...state, done: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(cmd: ReadingGroupCommand, state: ReadingGroupState): ReadingGroupEvent[] {
  switch (cmd.type) {
    case "create":
      return state.id ? [] : [{ type: "Created", id: cmd.id }];
    case "join":
      return state.done ? [] : [{ type: "Joined" }];
    case "complete":
      return state.done ? [] : [{ type: "Completed" }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export interface EventStore {
  readStream(n: string): AsyncIterable<{ event: ReadingGroupEvent; revision: bigint }>;
  appendToStream(
    n: string,
    es: ReadonlyArray<ReadingGroupEvent>,
    o: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export async function handleCommand(
  command: ReadingGroupCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initial;
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  const events = decide(command, state);
  if (events.length > 0) {
    await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
  }
}
