```typescript
import { Effect } from "effect";

export type AOEvent =
  | { type: "Drafted"; id: string }
  | { type: "LineAdded" }
  | { type: "Placed"; on: string };
export type AOCommand =
  | { type: "draft"; id: string }
  | { type: "addLine" }
  | { type: "place"; on: string };
export type AOState = { id: string; lines: number; placed: boolean };

const initial: AOState = { id: "", lines: 0, placed: false };

function evolve(state: AOState, event: AOEvent): AOState {
  switch (event.type) {
    case "Drafted":
      return { id: event.id, lines: 0, placed: false };
    case "LineAdded":
      return { ...state, lines: state.lines + 1 };
    case "Placed":
      return { ...state, placed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(cmd: AOCommand, state: AOState): AOEvent[] {
  switch (cmd.type) {
    case "draft":
      return state.id ? [] : [{ type: "Drafted", id: cmd.id }];
    case "addLine":
      return state.placed ? [] : [{ type: "LineAdded" }];
    case "place":
      return state.lines > 0 && !state.placed ? [{ type: "Placed", on: cmd.on }] : [];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<{ event: AOEvent; revision: bigint }>;
  appendToStream(
    streamName: string,
    events: ReadonlyArray<AOEvent>,
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
}

export function handleCommand(
  command: AOCommand,
  ctx: { streamName: string; eventStore: EventStore },
) {
  return Effect.gen(function* () {
    const loaded = yield* Effect.promise(async () => {
      let state = initial;
      let expected: bigint | "no_stream" = "no_stream";
      for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
        state = evolve(state, event);
        expected = revision;
      }
      return { state, expected } as const;
    });
    const events = decide(command, loaded.state);
    if (events.length > 0) {
      yield* Effect.promise(() =>
        ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: loaded.expected }),
      );
    }
  });
}
```

decide is pure: given the current state and a command it returns events or throws a typed domain error.  The CommandHandler is the IO shell: it reads the stream, folds into state via evolve, calls decide, then appends the resulting events under the last observed revision. Pure core, imperative shell.

```typescript
export type RREvent =
  | { type: "Opened"; id: string; topic: string }
  | { type: "Answered"; on: string };
export type RRCommand = { type: "open"; id: string; topic: string } | { type: "answer"; on: string };
export type RRState = { id: string; answered: boolean };

const initial: RRState = { id: "", answered: false };
export class DomainError extends Error {}

function evolve(state: RRState, event: RREvent): RRState {
  switch (event.type) {
    case "Opened":
      return { id: event.id, answered: false };
    case "Answered":
      return { ...state, answered: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(command: RRCommand, state: RRState): RREvent[] {
  switch (command.type) {
    case "open":
      if (state.id !== "") throw new DomainError("already open");
      return [{ type: "Opened", id: command.id, topic: command.topic }];
    case "answer":
      if (state.answered) throw new DomainError("already answered");
      if (state.id === "") throw new DomainError("not open");
      return [{ type: "Answered", on: command.on }];
    default: {
      const _: never = command;
      return _;
    }
  }
}

export interface EventStore {
  readStream(n: string): AsyncIterable<{ event: RREvent; revision: bigint }>;
  appendToStream(n: string, e: ReadonlyArray<RREvent>, o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export async function handleCommand(
  command: RRCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  let state = initial;
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  const events = decide(command, state);
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
}
