```typescript
export type InterlibraryEvent =
  | { type: "Requested"; id: string; title: string }
  | { type: "Shipped"; id: string }
  | { type: "Received"; id: string };

export interface CheckpointStore {
  read(subscriptionName: string): Promise<bigint | null>;
  write(subscriptionName: string, position: bigint): Promise<void>;
}

export interface EventIterator<E> {
  from(position: bigint | null): AsyncIterable<{ event: E; position: bigint }>;
}

export type ReadModel = Readonly<{
  rows: Record<string, { id: string; title: string; status: "requested" | "shipped" | "received" }>;
}>;

export const emptyModel: ReadModel = { rows: {} };

export function project(view: ReadModel, event: InterlibraryEvent): ReadModel {
  switch (event.type) {
    case "Requested":
      return { rows: { ...view.rows, [event.id]: { id: event.id, title: event.title, status: "requested" } } };
    case "Shipped": {
      const row = view.rows[event.id];
      return row ? { rows: { ...view.rows, [event.id]: { ...row, status: "shipped" } } } : view;
    }
    case "Received": {
      const row = view.rows[event.id];
      return row ? { rows: { ...view.rows, [event.id]: { ...row, status: "received" } } } : view;
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function runSubscription(
  name: string,
  checkpoints: CheckpointStore,
  source: EventIterator<InterlibraryEvent>,
  persist: (view: ReadModel) => Promise<void>,
): Promise<void> {
  const last = await checkpoints.read(name);
  let view = emptyModel;
  for await (const { event, position } of source.from(last)) {
    view = project(view, event);
    await persist(view);
    await checkpoints.write(name, position);
  }
}
```

Keep one checkpoint per subscription name in a small checkpoint store. On start read it, iterate events starting after that position, apply each event to the read model, then write the new checkpoint — always AFTER the projection has been applied so a crash cannot lose an apply without losing the checkpoint.

