    const start = yield* Effect.promise(() => checkpoints.read(name));
    yield* Effect.promise(async () => {
      let view = empty;
      for await (const { event, position } of source.from(start)) {
        view = project(view, event);
        await persist(view);
        await checkpoints.write(name, position);
      }
    });
  });
