```typescript
import { Effect } from "effect";

export type FineEvent =
  | { type: "FineIssued"; amount: number }
  | { type: "FinePaid"; amount: number }
  | { type: "FineWaived" };

export type FineState = { balance: number; closed: boolean };
export const initial: FineState = { balance: 0, closed: false };

export function when(state: FineState, event: FineEvent): FineState {
  switch (event.type) {
    case "FineIssued":
      return { balance: state.balance + event.amount, closed: false };
    case "FinePaid": {
      const next = state.balance - event.amount;
      return { balance: Math.max(0, next), closed: next <= 0 };
    }
    case "FineWaived":
      return { balance: 0, closed: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (state: S, event: E) => S,
  initialState: S,
) {
  return Effect.gen(function* () {
    const state = yield* Effect.promise(async () => {
      let acc = initialState;
      for await (const event of stream) {
        acc = fold(acc, event);
      }
      return acc;
    });
    return state;
  });
}

export function loadFine(stream: AsyncIterable<FineEvent>) {
  return aggregateStream<FineState, FineEvent>(stream, when, initial);
}
```

A projection's project folds a subset of events across many aggregates into a denormalised view on the read side. An aggregate's when folds one aggregate's entire event stream into its own state on the write side. aggregateStream is a generic helper that does the write-side fold in a single pass.

```typescript
export type CatalogEvent =
  | { type: "TitleAdded"; titleId: string }
  | { type: "TitleRemoved"; titleId: string }
  | { type: "CatalogPublished" };

export type CatalogState = {
  titles: ReadonlySet<string>;
  published: boolean;
};

export const initial: CatalogState = { titles: new Set<string>(), published: false };

export function when(state: CatalogState, event: CatalogEvent): CatalogState {
  switch (event.type) {
    case "TitleAdded": {
      const next = new Set(state.titles);
      next.add(event.titleId);
      return { ...state, titles: next };
    }
    case "TitleRemoved": {
      const next = new Set(state.titles);
      next.delete(event.titleId);
      return { ...state, titles: next };
    }
    case "CatalogPublished":
      return { ...state, published: true };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  fold: (s: S, e: E) => S,
  initialState: S,
): Promise<S> {
  let acc = initialState;
  for await (const event of stream) {
    acc = fold(acc, event);
  }
  return acc;
}

export async function loadCatalog(stream: AsyncIterable<CatalogEvent>): Promise<CatalogState> {
  return aggregateStream<CatalogState, CatalogEvent>(stream, when, initial);
}
```

