type RawCheckedOutV1 = { type: "CheckedOut"; version: 1; id: string; borrowerId: string; dueOn: string };
type RawCheckedOutV2 = { type: "CheckedOut"; version: 2; id: string; patron: string; dueOn: string };
type RawReturnedV1 = { type: "Returned"; version: 1; on: string };
type RawEvent = RawCheckedOutV1 | RawCheckedOutV2 | RawReturnedV1;

export class UnknownEventError extends Error {}

function isRaw(raw: unknown): raw is RawEvent {
  return typeof raw === "object" && raw !== null && "type" in raw && "version" in raw;
}

export function upcast(raw: unknown): CurrentBookLoanEvent {
  if (!isRaw(raw)) throw new UnknownEventError("not an event");
  switch (raw.type) {
    case "CheckedOut":
      if (raw.version === 1) {
        return { type: "CheckedOut", version: 2, id: raw.id, patron: raw.borrowerId, dueOn: raw.dueOn };
      }
      return { type: "CheckedOut", version: 2, id: raw.id, patron: raw.patron, dueOn: raw.dueOn };
    case "Returned":
      return { type: "Returned", version: 1, on: raw.on };
    default: {
      const _: never = raw;
      throw new UnknownEventError("unknown event");
    }
  }
}

export interface EventStore {
  readStream(streamName: string): AsyncIterable<unknown>;
}

export async function readAndUpcast(store: EventStore, streamName: string): Promise<CurrentBookLoanEvent[]> {
  const out: CurrentBookLoanEvent[] = [];
  for await (const raw of store.readStream(streamName)) {
    out.push(upcast(raw));
  }
  return out;
}
```

Tag every stored event with a version. At read time, upcast pattern-matches on (type, version) and rewrites older shapes into the current discriminated union. Only the upcast function knows about old shapes; the domain model never sees them.

