```typescript
export type CatalogEvent =
  | { type: "TitleAdded"; titleId: string; genre: string }
  | { type: "TitleRemoved"; titleId: string; genre: string };

export type CatalogView = { titles: Record<string, string>; counts: Record<string, number> };
export const empty: CatalogView = { titles: {}, counts: {} };

export function project(view: CatalogView, event: CatalogEvent): CatalogView {
  switch (event.type) {
    case "TitleAdded":
      return {
        titles: { ...view.titles, [event.titleId]: event.genre },
        counts: { ...view.counts, [event.genre]: (view.counts[event.genre] ?? 0) + 1 },
      };
    case "TitleRemoved": {
      const { [event.titleId]: _drop, ...rest } = view.titles;
      const prev = view.counts[event.genre] ?? 0;
      const next = prev - 1;
      const counts = next <= 0
        ? Object.fromEntries(Object.entries(view.counts).filter(([k]) => k !== event.genre))
        : { ...view.counts, [event.genre]: next };
      return { titles: rest, counts };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface Pager<E> {
  readBatch(from: bigint, size: number): Promise<{ events: ReadonlyArray<{ event: E; revision: bigint }>; next: bigint | null }>;
}

export async function rebuild(options: {
  from: bigint;
  batchSize: number;
  pager: Pager<CatalogEvent>;
  persist: (view: CatalogView, cursor: bigint) => Promise<void>;
}): Promise<void> {
  let view = empty;
  let cursor: bigint | null = options.from;
  while (cursor !== null) {
    const batch = await options.pager.readBatch(cursor, options.batchSize);
    for (const { event, revision } of batch.events) {
      view = project(view, event);
      cursor = revision;
    }
    await options.persist(view, cursor);
    cursor = batch.next;
  }
}
```

A rebuild is a chunked loop over the event store. Each iteration reads a batch, projects it, persists the view plus the cursor, and advances. A `from` option lets the next crash resume at the last persisted revision so rebuilds do not have to restart.

```typescript
export type DCEvent = { type: "CopyAdded"; id: string } | { type: "CopyRemoved"; id: string };
export type DCView = { active: Set<string> };
export const empty: DCView = { active: new Set<string>() };

export function project(view: DCView, event: DCEvent): DCView {
  switch (event.type) {
    case "CopyAdded": {
      const next = new Set(view.active);
      next.add(event.id);
      return { active: next };
    }
    case "CopyRemoved": {
      const next = new Set(view.active);
      next.delete(event.id);
      return { active: next };
    }
    default: {
      const _: never = event;
      return _;
    }
  }
}

export interface BatchReader<E> {
  readBatch(from: bigint, size: number): Promise<{ events: ReadonlyArray<{ event: E; revision: bigint }>; done: boolean }>;
}

export async function rebuild(options: {
  from: bigint;
  batchSize: number;
  reader: BatchReader<DCEvent>;
  persist: (view: DCView, cursor: bigint) => Promise<void>;
  onProgress?: (cursor: bigint) => void;
}): Promise<void> {
  let view = empty;
  let cursor = options.from;
  while (true) {
    const batch = await options.reader.readBatch(cursor, options.batchSize);
    for (const { event, revision } of batch.events) {
      view = project(view, event);
      cursor = revision;
    }
    await options.persist(view, cursor);
    options.onProgress?.(cursor);
    if (batch.done) return;
  }
}
```

```typescript
export type PEvent =
  | { type: "Registered"; id: string; title: string }
  | { type: "IssuePublished"; id: string; issueId: string };
export type PCommand =
  | { type: "register"; id: string; title: string }
  | { type: "publishIssue"; id: string; issueId: string };
export type PState = { id: string; title: string; issues: ReadonlyArray<string> };

const initial: PState = { id: "", title: "", issues: [] };
export class DomainError extends Error {}

function evolve(state: PState, event: PEvent): PState {
  switch (event.type) {
    case "Registered":
      return { id: event.id, title: event.title, issues: [] };
    case "IssuePublished":
      return { ...state, issues: [...state.issues, event.issueId] };
    default: {
      const _: never = event;
      return _;
    }
  }
}

function decide(cmd: PCommand, state: PState): PEvent[] {
  switch (cmd.type) {
    case "register":
      return state.id ? [] : [{ type: "Registered", id: cmd.id, title: cmd.title }];
    case "publishIssue":
      if (!state.id) throw new DomainError("not registered");
      return [{ type: "IssuePublished", id: cmd.id, issueId: cmd.issueId }];
    default: {
      const _: never = cmd;
      return _;
    }
  }
}

export interface EventStore {
  readStream(n: string): AsyncIterable<{ event: PEvent; revision: bigint }>;
  appendToStream(n: string, e: ReadonlyArray<PEvent>, o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export type QueryView = { id: string; title: string; issueCount: number };
export interface ReadStore {
  get(id: string): Promise<QueryView | null>;
}

export async function handleCommand(command: PCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void> {
  let state = initial;
  let expected: bigint | "no_stream" = "no_stream";
  for await (const { event, revision } of ctx.eventStore.readStream(ctx.streamName)) {
    state = evolve(state, event);
    expected = revision;
  }
  const events = decide(command, state);
  if (events.length) await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision: expected });
}

// NOTE: the read store is eventually consistent with the event store; a write
// may not appear in queryView until the projection subscription catches up.
export async function queryView(store: ReadStore, id: string): Promise<QueryView | null> {
  return store.get(id);
}
```

Writes and reads share the event definition but not the state type. Writes use Decider + eventStore.appendToStream; reads use a denormalised view stored in a read-side DB populated by a projection. The two sides are independent functions connected only by the event log.

```typescript
export type CatalogWriteEvent = { type: "TitleAdded"; id: string } | { type: "TitleRemoved"; id: string };
export type CatalogCommand = { type: "addTitle"; id: string } | { type: "removeTitle"; id: string };

