export type ProcessEvent =
  | { type: "AcquisitionPlaced"; id: string; vendor: string }
  | { type: "AcquisitionReceived"; id: string; on: string }
  | { type: "UnrelatedHolidayMarked" };

export type ProcessCommand =
  | { type: "ScheduleDelivery"; id: string; vendor: string }
  | { type: "CloseAcquisition"; id: string };

export function react(event: ProcessEvent): ProcessCommand | null {
  switch (event.type) {
    case "AcquisitionPlaced":
      return { type: "ScheduleDelivery", id: event.id, vendor: event.vendor };
    case "AcquisitionReceived":
      return { type: "CloseAcquisition", id: event.id };
    case "UnrelatedHolidayMarked":
      return null;
    default: {
      const _: never = event;
      return _;
    }
  }
}

