  readStream(streamName: string): AsyncIterable<{ event: ProcessEvent }>;
}

export async function driveSaga(store: EventStore, streamName: string): Promise<ProcessCommand[]> {
  const out: ProcessCommand[] = [];
  for await (const { event } of store.readStream(streamName)) {
    const next = react(event);
    if (next !== null) out.push(next);
  }
  return out;
}
```

A process manager is just a pure function (event) => Command | null.  The saga stays stateless by relying on the downstream aggregates' streams to carry state; events it does not care about return null.

