export type PeriodicalEvent = { type: string; data: Readonly<Record<string, unknown>> };

export interface OutboxRow {
  id: string;
  payload: string;
  publishedAt: string | null;
}

export interface Transaction {
  appendToStream(
    streamName: string,
    events: ReadonlyArray<PeriodicalEvent>,
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<void>;
  insertOutboxRows(rows: ReadonlyArray<OutboxRow>): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

export interface UnitOfWork {
  begin(): Promise<Transaction>;
}

// A separate background publisher polls the outbox table, publishes each row
// to the message broker, and marks it published by setting publishedAt.
// Publication is NOT implemented here so the transaction stays atomic and
// cheap; the publisher is idempotent and can be retried safely.
export async function appendWithOutbox(
  uow: UnitOfWork,
  streamName: string,
  events: ReadonlyArray<PeriodicalEvent>,
  rows: ReadonlyArray<OutboxRow>,
  expectedRevision: bigint | "no_stream" | "any",
): Promise<void> {
  const tx = await uow.begin();
  try {
    await tx.appendToStream(streamName, events, { expectedRevision });
    await tx.insertOutboxRows(rows);
    await tx.commit();
  } catch (error) {
    await tx.rollback();
    throw error;
  }
}
