export type ReadingGroupEvent = { type: string; data: Readonly<Record<string, unknown>> };

export interface EventStore {
  appendToStream(
    streamName: string,
    events: ReadonlyArray<ReadingGroupEvent>,
    options: { expectedRevision: bigint | "no_stream" | "any" },
  ): Promise<{ nextExpectedRevision: bigint; conflict?: true }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly streamName: string) {
    super("concurrency conflict on " + streamName);
  }
}

export async function appendToStream(
  store: EventStore,
  streamName: string,
  events: ReadonlyArray<ReadingGroupEvent>,
  expected: bigint | "no_stream" | "any",
): Promise<bigint> {
  const result = await store.appendToStream(streamName, events, { expectedRevision: expected });
  if (result.conflict) throw new ConcurrencyConflict(streamName);
  return result.nextExpectedRevision;
}
