Type the event iterable locally so you do not drag in a specific client package. A generic helper wraps `for await` inside an async function and returns the collected array — small, testable, and easy to mock.

```typescript
export type BookLoanEvent =
  | { type: "CheckedOut"; id: string }
  | { type: "Returned"; on: string };

export interface EventStore<E> {
  readStream(streamName: string): AsyncIterable<{ event: E; revision: bigint }>;
}

export async function readStreamToArray<E>(
  store: EventStore<E>,
  streamName: string,
): Promise<ReadonlyArray<{ event: E; revision: bigint }>> {
  const out: Array<{ event: E; revision: bigint }> = [];
  for await (const chunk of store.readStream(streamName)) {
    out.push(chunk);
  }
  return out;
}

export async function countLoanEvents(store: EventStore<BookLoanEvent>, streamName: string): Promise<number> {
  const events = await readStreamToArray(store, streamName);
  return events.length;
